class Solution {
public:
    bool isPalindrome(string s) {    
        int n = s.size();
        for(int x = 0, y = n-1; x < y; x++, y--){
            while(x < n && !isalnum(s[x])){
                x++;
            }
            while(y > 0 && !isalnum(s[y])){
                y--;
            }
            if(x >= y)
                return true;

            if(toupper(s[x]) != toupper(s[y]))
                return false;
        }
        return true;

    }
};
